Question: How many consecutive days was A4F_28771's sleep_points in stress_daily_scores higher than the average across all users, starting from 2022-06-13?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH avg_sleep_points AS (
    SELECT AVG(sleep_points) AS avg_points
    FROM stress_daily_scores
    WHERE DATE(ts) >= '2022-06-13'
),
consecutive_days AS (
    SELECT DATE(ts) AS date, sleep_points
    FROM stress_daily_scores
    WHERE id = 'A4F_28771' AND DATE(ts) >= '2022-06-13' AND sleep_points > (SELECT avg_points FROM avg_sleep_points)
)
SELECT COUNT(*) AS consecutive_days_count
FROM (
    SELECT date, 
           @prev_date := IF(@prev_date IS NULL OR DATE_SUB(date, INTERVAL 1 DAY) <> @prev_date, date, @prev_date) AS prev_date,
           @row_num := IF(@prev_date IS NULL OR DATE_SUB(date, INTERVAL 1 DAY) <> @prev_date, @row_num + 1, @row_num) AS row_num
    FROM consecutive_days, (SELECT @prev_date := NULL, @row_num := 0) AS vars
    ORDER BY date
) AS grouped_days
WHERE row_num = 1;

